Here's the pattern for testing async code with cancellation and timeouts in MSTest:

```csharp
[TestClass]
public class DataFetcherTests
{
    private MockHttpMessageHandler _handler = null!;
    private DataFetcher _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _handler = new MockHttpMessageHandler();
        _sut = new DataFetcher(new HttpClient(_handler));
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        _handler.Response = new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello")
        };

        var result = await _sut.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsHttpRequestException_OnFailure()
    {
        _handler.Response = new HttpResponseMessage(HttpStatusCode.InternalServerError);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => _sut.FetchAsync("https://example.com"));
    }

    // Cancellation: pre-cancelled token
    [TestMethod]
    public async Task FetchAsync_ThrowsWhenAlreadyCancelled()
    {
        var cts = new CancellationTokenSource();
        cts.Cancel();

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => _sut.FetchAsync("https://example.com", cts.Token));
    }

    // Cancellation: cancelled during execution
    [TestMethod]
    public async Task FetchAsync_ThrowsWhenCancelledDuringRequest()
    {
        var cts = new CancellationTokenSource();
        _handler.OnSend = () => cts.Cancel(); // cancel mid-flight
        _handler.Response = new HttpResponseMessage(HttpStatusCode.OK);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => _sut.FetchAsync("https://example.com", cts.Token));
    }

    // Timeout: use [Timeout] to guard against tests hanging
    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        _handler.Response = new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("fast")
        };

        var result = await _sut.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }

    // Simple test handler
    private class MockHttpMessageHandler : HttpMessageHandler
    {
        public HttpResponseMessage Response { get; set; } = new(HttpStatusCode.OK);
        public Action? OnSend { get; set; }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            OnSend?.Invoke();
            cancellationToken.ThrowIfCancellationRequested();
            await Task.Yield(); // simulate async work
            return Response;
        }
    }
}
```

**Key points:**

- **Mock at `HttpMessageHandler`**, not `HttpClient` — this is the standard seam for HTTP testing.
- **`[Timeout(ms)]`** prevents a test from hanging forever if the async call never completes. It's a safety net, not a behavioral assertion.
- **Pre-cancelled token** tests the guard-clause path; **cancel-during-send** tests the cooperative cancellation path.
- Always use `async Task` return type — never `async void` — so MSTest properly awaits and reports failures.
